<?php
namespace App\Http\Controllers\Fundraiser;
use App\Http\Controllers\Controller; use App\Http\Requests\StoreCampaignRequest; use App\Http\Requests\UpdateCampaignRequest; use App\Models\Campaign; use App\Models\CampaignCategory; use App\Repositories\CampaignRepository; use App\Services\CampaignService; use Illuminate\Http\Request;
class CampaignController extends Controller { public function __construct(private CampaignRepository $repo, private CampaignService $service) {} public function index(Request $request) { return view('fundraiser.campaigns.index',['campaigns'=>$this->repo->dashboardList($request->user()->id)]); } public function create() { return view('fundraiser.campaigns.form',['campaign'=>new Campaign(),'categories'=>CampaignCategory::all()]); } public function store(StoreCampaignRequest $request) { $this->service->store($request->validated(),$request->user()->id); return redirect()->route('fundraiser.campaigns.index')->with('success','Campaign dibuat dan menunggu verifikasi.'); } public function edit(Campaign $campaign) { abort_unless($campaign->fundraiser_id === request()->user()->id,403); return view('fundraiser.campaigns.form',['campaign'=>$campaign,'categories'=>CampaignCategory::all()]); } public function update(UpdateCampaignRequest $request, Campaign $campaign) { abort_unless($campaign->fundraiser_id === $request->user()->id,403); $this->service->update($campaign,$request->validated()); return back()->with('success','Campaign diperbarui.'); } }
